SELECT SUM(population) AS total_population
FROM family_demographics
WHERE year = 2020;

SELECT number_of_families
FROM family_compositions
WHERE family_type = 'B' AND family_structure = 'Single parent';

SELECT AVG(average_age) AS avg_age_of_two_parent_households
FROM family_compositions
WHERE family_structure = 'Two-parent household';

SELECT AVG(number_of_children) AS avg_children, AVG(average_age) AS avg_age
FROM family_compositions
WHERE family_type = 'B';

SELECT family_structure, average_age
FROM family_compositions
ORDER BY average_age DESC;

SELECT AVG(age) AS average_age
FROM family_members
WHERE gender = 'male';
